        // compte les CORROMPU, affiche le total
    }
}

chapters.correction:
class Program {
    static void Main() {
        string[] secteurs = {"OK", "CORROMPU", "CORROMPU", "OK"};
        int count = 0;
        foreach (string s in secteurs) {
            if (s == "CORROMPU") count++;
        }
        System.Console.WriteLine("Secteurs corrompus : " + (count));
    }
}

chapters.teach:
En C#, `Main` reçoit les arguments par `string[] args` : `args[0]` est le premier argument passé au programme.

```csharp
class Program {
    static void Saluer(string x) {
        System.Console.WriteLine("Bonjour " + (x));
    }
    static void Main(string[] args) {
        Saluer(args[0]);
    }
}
```

Lancé avec l'argument `Monde`, il affiche : `Bonjour Monde`.

